import * as XLSX from 'xlsx';
import dayjs from 'dayjs';

export const processCombinedData = (csvData, excelRaw, proyectadoManual = 108000) => {
  if (!csvData || !excelRaw) return null;

  try {
    // --- 1. PROCESAR EXCEL (EASY DOCKING) ---
    const workbook = XLSX.read(excelRaw, { type: 'array' });
    const sheet = workbook.Sheets[workbook.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json(sheet, { header: 1 });

    const headers = rows[3]?.map(h => String(h || "").trim()) || [];
    const dataRows = rows.slice(4);

    const easyDockingClean = dataRows.map(row => {
      let obj = {};
      headers.forEach((h, i) => obj[h] = row[i]);
      return obj;
    }).filter(item => 
      String(item['TIPO DE OPERACION'] || "").toUpperCase().includes("DESCARGA") && 
      String(item['Accion'] || "").toLowerCase() === "add"
    );

    // --- 2. LÓGICA DE TIEMPO (HASTA LAS 22:00) ---
    const ahora = dayjs();
    const horaCierre = dayjs().set('hour', 22).set('minute', 0).set('second', 0);
    let horasRestantes = horaCierre.diff(ahora, 'hour', true);
    if (horasRestantes <= 0) horasRestantes = 0.5;

    // --- 3. CÁLCULOS POR TIPO DE VEHÍCULO (MATRIX) ---
    const getMatrixVelocity = (tipos, metaPiezas) => {
      const filtrados = easyDockingClean.filter(d => 
        tipos.some(t => String(d['TRANSPORTE'] || "").includes(t))
      );
      const descargadas = filtrados.reduce((acc, curr) => acc + (parseFloat(curr['CANT PAQUETES']) || 0), 0);
      const objHora = Math.round((metaPiezas - descargadas) / horasRestantes);
      return objHora > 0 ? objHora : 0;
    };

    // --- 4. KPIs GLOBALES ---
    const totalArribadosFisicos = easyDockingClean.reduce((acc, curr) => acc + (parseFloat(curr['CANT PAQUETES']) || 0), 0);
    const totalSistema = csvData.length; // Cada fila del CSV es una pieza

    return {
      kpis: {
        proyectado: proyectadoManual.toLocaleString(),
        arribados: totalArribadosFisicos.toLocaleString(),
        total: totalSistema.toLocaleString(),
        // Obj x Hora Global
        descargaHora: Math.round((proyectadoManual - totalSistema) / horasRestantes).toLocaleString(),
        arribadoBipeado: (totalArribadosFisicos - totalSistema).toLocaleString(),
        proyectadoBipeado: (proyectadoManual - totalSistema).toLocaleString(),
        pArribado: Math.round((totalArribadosFisicos / proyectadoManual) * 100) || 0,
        pBipeo: Math.round((totalSistema / proyectadoManual) * 100) || 0,
        velocidadReal: 90
      },
      matrix: {
        chasis: getMatrixVelocity(['Chasis'], 60000), // Meta ejemplo 60k
        camioneta: getMatrixVelocity(['Camioneta', 'Camioneta MELI'], 30000), // Meta ejemplo 30k
        semi: getMatrixVelocity(['Semi'], 18000) // Meta ejemplo 18k
      },
      chartData: [], 
      tableData: []
    };
  } catch (e) {
    console.error("Error procesando:", e);
    return null;
  }
};
